 80→export function HomeFeedScreen({navigation}: Props) {
 81→  const {user} = useAuth();
 82→  const [refreshing, setRefreshing] = useState(false);
 83→
 84→  const feedQuery = useInfiniteQuery({
 85→    queryKey: ['feed', user?.id],
 86→    queryFn: ({pageParam}) => mobileApi.getJournals(pageParam ?? null, PAGE_SIZE, user?.id),
 87→    initialPageParam: null as string | null,
 88→    getNextPageParam: lastPage => getNextCursor(lastPage),
 89→  });
 90→
 91→  const posts = useMemo(
 92→    () => feedQuery.data?.pages.flatMap(page => page.data ?? []) ?? [],
 93→    [feedQuery.data?.pages],
 94→  );
 95→
 96→  const onRefresh = async () => {
 97→    setRefreshing(true);
 98→    try {
 99→      await feedQuery.refetch();
100→    } finally {
101→      setRefreshing(false);
102→    }
103→  };
104→
105→  return (
106→    <Screen scroll={false}>
107→      <View style={styles.headerRow}>
108→        <Text style={styles.title}>Home Feed</Text>
109→        <PrimaryButton
110→          label="Write"
111→          onPress={() => navigation.navigate('JournalEditor', {mode: 'create'})}
112→        />
113→      </View>
114→
115→      <View style={styles.quickActions}>
116→        <PrimaryButton
117→          label="Canvas"
118→          onPress={() => navigation.navigate('Canvas')}
119→          kind="secondary"
120→        />
121→        <PrimaryButton
122→          label="Freedom Wall"
123→          onPress={() => navigation.navigate('FreedomWall')}
124→          kind="secondary"
125→        />
126→        <PrimaryButton
127→          label="Universe"
128→          onPress={() => navigation.navigate('Universe')}
129→          kind="secondary"
130→        />
131→      </View>
132→
133→      <FlatList
134→        data={posts}
135→        onRefresh={onRefresh}
136→        refreshing={refreshing}
137→        onEndReachedThreshold={0.25}
138→        onEndReached={() => {
139→          if (feedQuery.hasNextPage && !feedQuery.isFetchingNextPage) {
140→            feedQuery.fetchNextPage();
141→          }
142→        }}
143→        ListEmptyComponent={
144→          <View style={styles.emptyCard}>
145→            <Text style={styles.emptyTitle}>No posts yet</Text>
146→            <Text style={styles.emptyText}>
147→              Pull to refresh or create your first journal post.
148→            </Text>
149→          </View>
150→        }
151→        keyExtractor={item => item.id}
152→        renderItem={({item}) => {
153→          const preview = extractPlainText(item.content).slice(0, 180);
154→          const likeCount = resolveCount(item.like_count, item.likes_count);
155→          const commentCount = resolveCount(item.comment_count, item.comments_count);
156→          const bookmarkCount = resolveCount(item.bookmark_count);
157→
158→          return (
159→            <Pressable
160→              onPress={() => navigation.navigate('PostDetail', {journalId: item.id})}
161→              style={({pressed}) => [styles.postCard, pressed && styles.postCardPressed]}>
162→              <Text style={styles.postTitle}>{item.title || 'Untitled Post'}</Text>
163→              <Text style={styles.postMeta}>
164→                {item.users?.name || 'Unknown author'}
165→                {item.post_type ? ` • ${item.post_type}` : ''}
166→              </Text>
167→              <Text style={styles.postBody}>
168→                {preview || 'No preview text available.'}
169→              </Text>
170→              <View style={styles.statsRow}>
171→                <Text style={styles.statText}>{`Likes ${likeCount}`}</Text>
172→                <Text style={styles.statText}>{`Comments ${commentCount}`}</Text>
173→                <Text style={styles.statText}>{`Bookmarks ${bookmarkCount}`}</Text>
174→              </View>
175→            </Pressable>
176→          );
177→        }}
178→      />
179→    </Screen>
180→  );
181→}
