 22→
 23→type Props = NativeStackScreenProps<RootStackParamList, 'PostDetail'>;
 24→
 25→const toCount = (value: unknown): number | null => {
 26→  const parsed = Number(value);
 27→  if (!Number.isFinite(parsed) || parsed < 0) {
 28→    return null;
 29→  }
 30→  return parsed;
 31→};
 32→
 33→const resolveCount = (
 34→  aggregate: Array<{count?: number}> | undefined,
 35→  fallback?: number,
 36→): number => {
 37→  const aggregateCount = toCount(aggregate?.[0]?.count);
 38→  if (aggregateCount != null) {
 39→    return aggregateCount;
 40→  }
 41→  return toCount(fallback) ?? 0;
 42→};
 43→
 44→const formatTimestamp = (value: string | undefined): string => {
 45→  if (!value) {
 46→    return '';
 47→  }
 48→  const date = new Date(value);
 49→  if (Number.isNaN(date.getTime())) {
 50→    return value;
 51→  }
 52→  return date.toLocaleString();
 53→};
