176→      headers: {
177→        ...authHeaders(token),
178→      },
179→    });
180→  },
181→
182→  async createRepost(
183→    token: string,
184→    payload: {sourceJournalId: string; caption?: string},
185→  ): Promise<{message?: string}> {
186→    return apiRequest<{message?: string}>('/repost', {
187→      method: 'POST',
188→      headers: {
189→        ...authHeaders(token),
190→        'Content-Type': 'application/json',
191→      },
192→      body: JSON.stringify(payload),
193→    });
194→  },
195→};
