 15→const formatTimestamp = (value?: string): string => {
 16→  if (!value) {
 17→    return '';
 18→  }
 19→  const date = new Date(value);
 20→  if (Number.isNaN(date.getTime())) {
 21→    return value;
 22→  }
 23→  return date.toLocaleString();
 24→};
 25→
 26→const formatTitle = (item: NotificationItem): string => {
 27→  if (item.message) {
 28→    return item.message;
 29→  }
 30→
 31→  const senderName = item.users?.name || 'Someone';
 32→  switch (item.type) {
 33→    case 'like':
 34→      return `${senderName} liked your post`;
 35→    case 'comment':
 36→      return `${senderName} commented on your post`;
 37→    case 'repost':
 38→      return `${senderName} reposted your post`;
 39→    case 'reply':
 40→      return `${senderName} replied`;
 41→    case 'match':
 42→      return `${senderName} matched with you`;
 43→    default:
 44→      return 'Notification';
 45→  }
 46→};
 47→
 48→const formatContext = (item: NotificationItem): string => {
 49→  const journalTitle = item.journals?.title?.trim();
 50→  if (journalTitle) {
 51→    return journalTitle;
 52→  }
 53→  const opinionText = item.opinions?.opinion?.trim();
 54→  if (opinionText) {
 55→    return opinionText.length > 120 ? `${opinionText.slice(0, 117)}...` : opinionText;
 56→  }
 57→  return '';
 58→};
 59→
 60→const getSource = (item: NotificationItem): 'journal' | 'opinion' => {
 61→  if (item.source === 'opinion' || item.opinion_id) {
 62→    return 'opinion';
 63→  }
 64→  return 'journal';
 65→};
 66→
 67→export function NotificationsScreen(_: Props) {
 68→  const {session} = useAuth();
 69→  const token = session?.access_token ?? '';
 70→  const userId = session?.user.id ?? '';
 71→
 72→  const notificationsQuery = useQuery({
 73→    queryKey: ['notifications', userId],
 74→    enabled: Boolean(token),
 75→    queryFn: () => mobileApi.getNotifications(token, null, 20),
 76→  });
 77→
 78→  const unreadCountQuery = useQuery({
 79→    queryKey: ['notification-count', userId],
 80→    enabled: Boolean(token && userId),
 81→    queryFn: () => socialApi.getNotificationsCount(token, userId),
 82→  });
 83→
 84→  const markReadMutation = useMutation({
 85→    mutationFn: (args: {notifId: string; source: 'journal' | 'opinion'}) =>
 86→      socialApi.markNotificationRead(token, args.notifId, args.source),
 87→    onSuccess: async () => {
 88→      await Promise.all([
 89→        queryClient.invalidateQueries({queryKey: ['notifications', userId]}),
 90→        queryClient.invalidateQueries({queryKey: ['notification-count', userId]}),
 91→      ]);
 92→    },
 93→  });
 94→
 95→  const deleteMutation = useMutation({
 96→    mutationFn: (args: {notifId: string; source: 'journal' | 'opinion'}) =>
 97→      socialApi.deleteNotification(token, args.notifId, args.source),
 98→    onSuccess: async () => {
 99→      await Promise.all([
100→        queryClient.invalidateQueries({queryKey: ['notifications', userId]}),
101→        queryClient.invalidateQueries({queryKey: ['notification-count', userId]}),
102→      ]);
103→    },
104→  });
105→
106→  return (
107→    <Screen>
108→      <Text style={styles.title}>
109→        {`Notifications (${unreadCountQuery.data?.count ?? 0})`}
110→      </Text>
111→
112→      {!session?.access_token ? (
113→        <Text style={styles.textMuted}>Log in to load notifications.</Text>
114→      ) : notificationsQuery.isLoading ? (
115→        <View style={styles.loadingRow}>
116→          <ActivityIndicator color={colors.accent} />
117→          <Text style={styles.textMuted}>Loading notifications...</Text>
118→        </View>
119→      ) : notificationsQuery.isError ? (
120→        <Text style={styles.error}>Could not load notifications.</Text>
121→      ) : notificationsQuery.data?.data?.length ? (
122→        notificationsQuery.data.data.map(item => {
123→          const source = getSource(item);
124→          const subtitle = formatContext(item);
125→          return (
126→          <View key={item.id} style={styles.card}>
127→            <Text style={styles.cardTitle}>{formatTitle(item)}</Text>
128→            {!!subtitle && (
129→              <Text style={styles.cardBody}>{subtitle}</Text>
130→            )}
131→            <Text style={styles.textMuted}>{formatTimestamp(item.created_at)}</Text>
132→            <View style={styles.actionsRow}>
133→              {!item.read && (
134→                <Pressable
135→                  disabled={markReadMutation.isPending}
136→                  onPress={() => markReadMutation.mutate({notifId: item.id, source})}
137→                  style={({pressed}) => [styles.pill, pressed && styles.pillPressed]}>
138→                  <Text style={styles.pillText}>Mark read</Text>
139→                </Pressable>
140→              )}
141→              <Pressable
142→                disabled={deleteMutation.isPending}
143→                onPress={() => deleteMutation.mutate({notifId: item.id, source})}
144→                style={({pressed}) => [styles.pill, pressed && styles.pillPressed]}>
145→                <Text style={styles.pillText}>Delete</Text>
146→              </Pressable>
147→            </View>
148→          </View>
149→          );
150→        })
151→      ) : (
152→        <Text style={styles.textMuted}>No notifications yet.</Text>
153→      )}
154→    </Screen>
155→  );
156→}
