 29→export function StoryDashboardScreen({navigation}: Props) {
 30→  const {session} = useAuth();
 31→  const token = session?.access_token ?? '';
 32→  const queryClient = useQueryClient();
 33→
 34→  const myStoriesQuery = useInfiniteQuery({
 35→    queryKey: ['stories-dashboard', token],
 36→    enabled: token.length > 0,
 37→    queryFn: ({pageParam}) => storyApi.getMyStories(token, {limit: 10, before: pageParam ?? null}),
 38→    initialPageParam: null as string | null,
 39→    getNextPageParam: page => getNext(page),
 40→  });
 41→
 42→  const deleteMutation = useMutation({
 43→    mutationFn: (storyId: string) => storyApi.deleteStory(token, storyId),
 44→    onSuccess: () => {
 45→      queryClient.invalidateQueries({queryKey: ['stories-dashboard', token]});
 46→      queryClient.invalidateQueries({queryKey: ['stories-browser']});
 47→    },
 48→  });
 49→
 50→  const stories = useMemo(
 51→    () => myStoriesQuery.data?.pages.flatMap(page => page.data ?? []) ?? [],
 52→    [myStoriesQuery.data?.pages],
 53→  );
 54→
 55→  const onDelete = (storyId: string, title: string) => {
 56→    Alert.alert('Delete story', `Delete "${title}"?`, [
 57→      {text: 'Cancel', style: 'cancel'},
 58→      {text: 'Delete', style: 'destructive', onPress: () => deleteMutation.mutate(storyId)},
 59→    ]);
 60→  };
 61→
 62→  return (
 63→    <Screen scroll={false}>
 64→      <View style={styles.header}>
 65→        <Text style={styles.title}>My Stories</Text>
 66→        <PrimaryButton
 67→          label="New Story"
