 69→        />
 70→      </View>
 71→
 72→      {!token ? (
 73→        <Text style={styles.meta}>Login required.</Text>
 74→      ) : myStoriesQuery.isLoading ? (
 75→        <View style={styles.loading}>
 76→          <ActivityIndicator color={colors.accent} />
 77→          <Text style={styles.meta}>Loading stories...</Text>
 78→        </View>
 79→      ) : (
 80→        <FlatList
 81→          data={stories}
 82→          keyExtractor={item => item.id}
 83→          onEndReachedThreshold={0.3}
 84→          onEndReached={() => {
 85→            if (myStoriesQuery.hasNextPage && !myStoriesQuery.isFetchingNextPage) {
 86→              myStoriesQuery.fetchNextPage();
